-- Turkish Banking System - Server Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nRegisterNetEvent('bank:server:deposit')\nAddEventHandler('bank:server:deposit', function(amount)\n    local src = source\n    local Player = QBCore.Functions.GetPlayer(src)\n    if not Player then return end\n    \n    if amount <= 0 or Player.PlayerData.money.cash < amount then\n        TriggerClientEvent('QBCore:Notify', src, 'Gecersiz tutar!', 'error')\n        return\n    end\n    \n    Player.Functions.RemoveMoney('cash', amount)\n    Player.Functions.AddMoney('bank', amount)\n    TriggerClientEvent('QBCore:Notify', src, 'Banka hesabiniza $' .. amount .. ' yatirildi', 'success')\nend)\n\nRegisterNetEvent('bank:server:withdraw')\nAddEventHandler('bank:server:withdraw', function(amount)\n    local src = source\n    local Player = QBCore.Functions.GetPlayer(src)\n    if not Player then return end\n    \n    if amount <= 0 or Player.PlayerData.money.bank < amount then\n        TriggerClientEvent('QBCore:Notify', src, 'Gecersiz islem!', 'error')\n        return\n    end\n    \n    Player.Functions.RemoveMoney('bank', amount)\n    Player.Functions.AddMoney('cash', amount)\n    TriggerClientEvent('QBCore:Notify', src, 'Banka hesabindan $' .. amount .. ' cekildi', 'success')\nend)\n\nprint('^2[Turkish Banking System] Yuklendi!^7')"